SELECT module_name, COUNT(*) AS frequency FROM (SELECT TRIM(SUBSTRING("content", POSITION('import ' IN "content") + 7, POSITION(' ' IN SUBSTRING("content", POSITION('import ' IN "content") + 7) || ' ') - 1)) AS module_name FROM "SAMPLE_CONTENTS" WHERE "sample_path" ILIKE '%.py' AND POSITION('import ' IN "content") > 0 UNION ALL SELECT TRIM(SUBSTRING("content", POSITION('from ' IN "content") + 5, POSITION(' ' IN SUBSTRING("content", POSITION('from ' IN "content") + 5) || ' ') - 1)) AS module_name FROM "SAMPLE_CONTENTS" WHERE "sample_path" ILIKE '%.py' AND POSITION('from ' IN "content") > 0 UNION ALL SELECT TRIM(SUBSTRING("content", POSITION('library(' IN "content") + 8, POSITION(')' IN SUBSTRING("content", POSITION('library(' IN "content") + 8) || ')') - 1)) AS module_name FROM "SAMPLE_CONTENTS" WHERE "sample_path" ILIKE '%.r' AND POSITION('library(' IN "content") > 0) AS modules GROUP BY module_name ORDER BY frequency DESC LIMIT 5 /* Extracting top 5 module names from Python and R scripts */
